            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Validate filter type
            # -------------------------------------------------------------------------
            allowed_filters = {"blur", "sharpen", "median"}
            if filter_type.lower() not in allowed_filters:
                raise ValueError(f"Unsupported filter_type '{filter_type}'. Allowed values: {sorted(allowed_filters)}")
        
            # -------------------------------------------------------------------------
            # Perform the filtering using Aspose.Imaging
            # -------------------------------------------------------------------------
