        @mcp.tool()
        async def imaging_resize_by_percentage(
            image_filename: str,
            scale_percent: float,
            output_filename: str | None = None,
        ) -> dict:
            """
            Resize an existing image by a percentage factor.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre-placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the source image.
                scale_percent: Scaling factor as a percentage, e.g. 50.0 for half size.
                output_filename: Bare filename for the resized image. None → temporary file.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str (bare name of the written file, present on success)
                }
        
            Raises:
                FileNotFoundError: If the source image does not exist.
                ValueError: If scale_percent is not positive.
        
            Example:
                result = await imaging_resize_by_percentage(
                    image_filename="photo.jpg",
                    scale_percent=75.0,
                    output_filename="photo_resized.jpg",
                )
            """
            # ---------- Resolve and validate input ----------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            # sanitize and ensure only the filename is used
            image_filename = Path(image_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(image_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            if scale_percent <= 0:
                raise ValueError("scale_percent must be a positive number")
        
            # ---------- Resolve output ----------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # keep original extension for the temporary file
                suffix = Path(image_filename).suffix or ".png"
                temp_path = temp_output_path("aspose_imaging_result", suffix)
                resolved_output = str(temp_path)  # Aspose expects a plain str
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ---------- Perform resize ----------
            import logging
            logger = logging.getLogger(__name__)
        
            try:
                from aspose.imaging import Image, ResizeType
        
                img = Image.load(str(resolved_input))
        
                # original dimensions
                orig_width = img.width
                orig_height = img.height
        
                new_width = int(orig_width * scale_percent / 100)
                new_height = int(orig_height * scale_percent / 100)
        
                img.resize(new_width, new_height, ResizeType.LANCZOS_RESAMPLE)
                img.save(str(resolved_output))
        
                return {
                    "status": "success",
                    "message": f"Image resized to {new_width}x{new_height}.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to resize image %s", image_filename)
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def imaging_crop_to_aspect_ratio(
            image_filename: str,
            aspect_width: int,
            aspect_height: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Crop an existing image to a specific aspect ratio while keeping the central region.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the source image. The file must already exist in ASPOSE_FILES_PATH.
                aspect_width: Width component of the desired aspect ratio (must be > 0).
                aspect_height: Height component of the desired aspect ratio (must be > 0).
                output_filename: Bare filename for the cropped image. If None, a temporary file is created.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (only on success)
                }
        
            Raises:
                FileNotFoundError: If the source image file does not exist.
                ValueError: If aspect_width or aspect_height are not positive integers.
        
            Example:
                result = await imaging_crop_to_aspect_ratio(
                    image_filename="photo.jpg",
                    aspect_width=16,
                    aspect_height=9,
                    output_filename="photo_cropped.jpg",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input / output paths (must be first statements)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            # sanitize and resolve input image
            image_filename = Path(image_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(image_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # validate aspect dimensions
            if aspect_width <= 0 or aspect_height <= 0:
                raise ValueError("aspect_width and aspect_height must be positive integers")
        
            # sanitize and resolve output image
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # keep original extension for the temp file
                ext = Path(image_filename).suffix or ".png"
                resolved_output = str(temp_output_path("aspose_imaging_result", ext))
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Perform cropping with Aspose.Imaging
            # ----------------------------------------------------------------------
            import logging
            logger = logging.getLogger(__name__)
        
            try:
                from aspose.imaging import Image, Rectangle
        
                # load image
                img = Image.load(str(resolved_input))
                orig_width = img.width
                orig_height = img.height
                logger.debug(
                    "Original size: %dx%d", orig_width, orig_height
                )
        
                # compute target rectangle
                desired_ratio = aspect_width / aspect_height
                current_ratio = orig_width / orig_height
        
                if current_ratio > desired_ratio:
                    # image is too wide → crop width
                    new_width = int(orig_height * desired_ratio)
                    new_height = orig_height
                    x = (orig_width - new_width) // 2
                    y = 0
                else:
                    # image is too tall → crop height
                    new_width = orig_width
                    new_height = int(orig_width / desired_ratio)
                    x = 0
                    y = (orig_height - new_height) // 2
        
                logger.debug(
                    "Cropping rectangle: x=%d, y=%d, w=%d, h=%d",
                    x,
                    y,
                    new_width,
                    new_height,
                )
        
                rect = Rectangle(x, y, new_width, new_height)
                img.crop(rect)
        
                # save result
                img.save(str(resolved_output))
                img.close()
        
                return {
                    "status": "success",
                    "message": "Image cropped to the requested aspect ratio.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to crop image: %s", exc)
                return {"status": "error", "message": str(exc)}

