        @mcp.tool()
        async def imaging_extract_exif(image_filename: str) -> dict:
            """
            Extract EXIF metadata from a JPEG image stored on the server.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the JPEG image, e.g. "photo.jpg". The file must already exist in ASPOSE_FILES_PATH.
        
            Returns:
                dict: A dictionary containing at minimum:
                    - "status": "success" or "error"
                    - "message": Human‑readable description
                    - EXIF fields (e.g. "make", "model", "date_time") when successful
        
            Raises:
                FileNotFoundError: If the specified image file does not exist.
                ValueError: If the file is not a JPEG image or contains no EXIF data.
        
            Example:
                >>> result = await imaging_extract_exif("portrait.jpg")
                >>> result["make"]
                'Canon'
            """
            # ----------------------------------------------------------------------
            # Resolve and validate the input filename
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            image_filename = Path(image_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(image_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # ----------------------------------------------------------------------
            # Imports required for Aspose.Imaging (lazy import as mandated)
            # ----------------------------------------------------------------------
            import logging
            from aspose.imaging import Image

            logger = logging.getLogger(__name__)

            try:
                exif_info: dict = {}

                with Image.load(str(resolved_input)) as img:
                    # isinstance(img, JpegImage) is unreliable under .NET interop — use hasattr instead
                    exif = getattr(img, "exif_data", None)
                    if exif is None:
                        raise ValueError(
                            f"No EXIF data found in '{image_filename}'. "
                            "Only JPEG images contain EXIF data."
                        )

                    # Direct attributes (if present)
                    for attr in ("make", "model", "date_time", "date_time_original", "date_time_digitized",
                                 "orientation", "x_resolution", "y_resolution", "flash", "focal_length",
                                 "exposure_time", "f_number", "iso_speed", "software", "artist",
                                 "copyright", "gps_latitude", "gps_longitude", "gps_altitude"):
                        val = getattr(exif, attr, None)
                        if val is not None and str(val).strip():
                            exif_info[attr] = str(val)

                    # Fallback: iterate over generic tags collection if available
                    if hasattr(exif, "tags"):
                        try:
                            for tag in exif.tags:
                                tag_name = getattr(tag, "name", None) or getattr(tag, "id", None)
                                tag_value = getattr(tag, "value", None)
                                if tag_name and tag_value is not None:
                                    exif_info[str(tag_name)] = str(tag_value)
                        except Exception as e:
                            logger.debug("Failed to iterate over exif.tags: %s", e)

                if not exif_info:
                    return {
                        "status": "success",
                        "message": f"Image '{image_filename}' loaded but contains no readable EXIF fields.",
                        "exif": {},
                    }

                return {
                    "status": "success",
                    "message": f"EXIF data extracted from {image_filename}.",
                    **exif_info,
                }

            except Exception as exc:
                logger.error("Error extracting EXIF from %s: %s", image_filename, exc)
                return {"status": "error", "message": str(exc)}

